import { writeOutput } from "./codegen";

const DOCS_URL = "https://docs.segmentapis.com/tag/Getting-Started/";
const PLACEHOLDER_VALUE = "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocal";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Segment Public API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:segment",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const segmentFirewall = {",
    '  name: "segment",',
    '  description: "Segment Public API",',
    "  placeholders: {",
    `    SEGMENT_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.segmentapis.com",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.SEGMENT_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [",
    "        {",
    '          name: "read",',
    '          description: "Read Segment resources",',
    '          rules: ["GET /{path+}"],',
    "        },",
    "        {",
    '          name: "write",',
    '          description: "Create, update, and delete Segment resources",',
    "          rules: [",
    '            "POST /{path+}",',
    '            "PUT /{path+}",',
    '            "PATCH /{path+}",',
    '            "DELETE /{path+}",',
    "          ],",
    "        },",
    "      ],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Segment firewall config...");
  const ts = generateTypeScript();
  writeOutput("segment", ts, import.meta.dirname);
}
